<?php
namespace app\Helpers; class ApiResponse{ public static function json(bool $success,string $message,mixed $data=null,array $errors=[],int $status=200):void{ http_response_code($status); header('Content-Type: application/json; charset=utf-8'); echo json_encode(['success'=>$success,'message'=>$message,'data'=>$data,'errors'=>$errors],JSON_UNESCAPED_UNICODE|JSON_PRETTY_PRINT); exit; } public static function success(string $message='Thao tác thành công',mixed $data=null,int $status=200):void{ self::json(true,$message,$data,[],$status); } public static function error(string $message='Có lỗi xảy ra',array $errors=[],int $status=400):void{ self::json(false,$message,null,$errors,$status); }}
